function App() {
  const products = [
    { id: 1, name: "💻 Laptop", price: 50000 },
    { id: 2, name: "📱 Mobile", price: 20000 },
    { id: 3, name: "🎧 Headphone", price: 3000 }
  ];

  return (
    <div>
      {products.map((product) => (
        <h2 key={product.id}>
          {product.name} - ₹{product.price}
        </h2>
      ))}
    </div>
  );
}

export default App;
